#include <bits/stdc++.h>
#define ull unsigned long long
#define mk make_pair
#define PII pair<int,int>
#define NoAns puts("-1");
#define FOR(i,j,k) for(int i=(j);i<=(k);++i)
#define ROF(i,j,k) for(int i=(j);i>=(k);--i)
#define FOI(a,b) for(auto a : b)
#define Yes puts("Yes");
#define No puts("No");
#define llinf 0x3f3f3f3f3f3f3f3f
#define inf 0x3f3f3f3f
#define ll long long
#define snd second
#define fst first
#define il inline
#define pb push_back
#define CI const int
#define cl(x) memset(x,0,sizeof x)
#define cli(x) memset(x,0x3f,sizeof x)
#define lowbit(x) (x&(-x))
#define wh while
#define gc() getchar()
#define pc(x) putchar(x)
#define NP namespace
using NP std;
il ll read()
{
    ll x=0,f=1;char ch=gc();
    wh(ch<'0'||ch>'9'){if(ch=='-')f=-1;ch=getchar();}
    wh(ch>='0'&&ch<='9'){x=x*10+ch-'0';ch=gc();}
    return x*f;
}
void write(ll x)
{
    if(x<0)pc('-'),x=-x;
    if(x>9)write(x/10);
    pc(x%10+'0');
}
void writeln(ll x)
{
    write(x);
    puts("");
    return;
}
CI MAXN=5e2+5;
int n,m,k;
vector<int> g[MAXN];
void BFS(int u)
{
	queue<int> q;
	q.push(u);
    FOR(i,1,k)
    {
		set<int> s;
        wh(q.size())
        {
            int l=q.size();
            FOR(i,1,l)
            {
                int t=q.front();
                q.pop();
                FOI(z,g[t])s.insert(z);
            }
        }
        FOI(x,s)q.push(x);
        write(s.size());pc(' ');
    }
}
int main(void) 
{
    n=read(),m=read(),k=read();
	FOR(i,1,m)
    {
		int u=read(),v=read();
		g[u].pb(v);
		g[v].pb(u);
	}
	FOR(i,1,n)
    {
		BFS(i);
        pc('\n');
	}
	return false;
}
